cd /Users/dh/Project/orbit 2>/dev/null || exit 0; errs=''; rc=0; for f in $(find plugins/orbit-base -name '*.sh' 2>/dev/null); do out=$(bash -n "$f" 2>&1); [ $? -ne 0 ] && { errs="${errs}
[bash -n FAIL] $f:
